#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long A,B; scanf("%lld %lld", &A, &B);
        long long left = 2*A; // compare with B
        if(left > B) printf("FIRST\n");
        else if(left < B) printf("SECOND\n");
        else printf("ANY\n");
    }
    return 0;
}

